  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { EventBus } from '../../src/events/event-bus.js';
import { EmailNotificationAdapter } from '../../src/adapters/email.adapter.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import type { Notification } from '../../src/models/notification.js';
import type { OrderCreatedEvent } from '../../src/events/event-types.js';

function makeNotification(overrides: Partial<Notification> = {}): Notification {
  return {
    id: 'notif-0001',
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation',
    body: 'Your order has been placed.',
    channel: 'email',
    status: 'sent',
    sentAt: new Date('2026-03-01T12:00:00Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('record', () => {
    it('should record a sent notification', () => {
      const notification = makeNotification();
      const log = historyService.record(notification);

      expect(log.id).toBe('log-0001');
      expect(log.notificationId).toBe('notif-0001');
      expect(log.recipient).toBe('alice@example.com');
      expect(log.channel).toBe('email');
      expect(log.type).toBe('order_confirmation');
      expect(log.status).toBe('sent');
      expect(log.timestamp).toEqual(new Date('2026-03-01T12:00:00Z'));
    });

    it('should record a failed notification with error', () => {
      const notification = makeNotification({
        status: 'failed',
        error: 'Invalid recipient',
      });
      const log = historyService.record(notification);

      expect(log.status).toBe('failed');
      expect(log.error).toBe('Invalid recipient');
    });

    it('should generate sequential log IDs', () => {
      const log1 = historyService.record(makeNotification({ id: 'notif-0001' }));
      const log2 = historyService.record(makeNotification({ id: 'notif-0002' }));

      expect(log1.id).toBe('log-0001');
      expect(log2.id).toBe('log-0002');
    });

    it('should persist to repository', () => {
      historyService.record(makeNotification());
      expect(repository.count()).toBe(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      historyService.record(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          type: 'order_confirmation',
          channel: 'email',
          status: 'sent',
          sentAt: new Date('2026-03-01T12:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'order_status_update',
          channel: 'email',
          status: 'failed',
          error: 'Delivery failed',
          sentAt: new Date('2026-03-02T12:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0003',
          recipient: 'alice@example.com',
          type: 'system_alert',
          channel: 'webhook',
          status: 'sent',
          sentAt: new Date('2026-03-03T12:00:00Z'),
        }),
      );
    });

    it('should query by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      expect(results.every((r) => r.recipient === 'alice@example.com')).toBe(true);
    });

    it('should query by type', () => {
      const results = historyService.query({ type: 'order_confirmation' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should query by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should query by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.status).toBe('failed');
    });

    it('should query by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-03-02T00:00:00Z'),
        endDate: new Date('2026-03-03T00:00:00Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('should combine multiple query filters', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        channel: 'email',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order_confirmation');
    });

    it('should return all logs with empty query', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      historyService.record(
        makeNotification({
          id: 'notif-0001',
          recipient: 'alice@example.com',
          type: 'order_confirmation',
          sentAt: new Date('2026-03-01T12:00:00Z'),
        }),
      );
      historyService.record(
        makeNotification({
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'order_confirmation',
          sentAt: new Date('2026-03-05T12:00:00Z'),
        }),
      );
    });

    it('should get logs by recipient', () => {
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
    });

    it('should get logs by type', () => {
      expect(historyService.getByType('order_confirmation')).toHaveLength(2);
    });

    it('should get logs by date range', () => {
      const results = historyService.getByDateRange(
        new Date('2026-03-04T00:00:00Z'),
        new Date('2026-03-06T00:00:00Z'),
      );
      expect(results).toHaveLength(1);
      expect(results[0]?.notificationId).toBe('notif-0002');
    });

    it('should get all logs', () => {
      expect(historyService.getAll()).toHaveLength(2);
    });

    it('should get count', () => {
      expect(historyService.getCount()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    it('should automatically log notifications sent through NotificationService', async () => {
      const eventBus = new EventBus();
      const emailAdapter = new EmailNotificationAdapter({ from: 'noreply@taskflow.com' });
      resetNotificationIdCounter();

      const notificationService = new NotificationService(
        eventBus,
        [emailAdapter],
        undefined,
        historyService,
      );

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const logs = historyService.getAll();
      expect(logs).toHaveLength(1);
      expect(logs[0]?.notificationId).toBe('notif-0001');
      expect(logs[0]?.recipient).toBe('alice@example.com');
      expect(logs[0]?.channel).toBe('email');
      expect(logs[0]?.type).toBe('order_confirmation');
      expect(logs[0]?.status).toBe('sent');
    });

    it('should not break NotificationService when history service is not provided', async () => {
      const eventBus = new EventBus();
      const emailAdapter = new EmailNotificationAdapter({ from: 'noreply@taskflow.com' });
      resetNotificationIdCounter();

      const notificationService = new NotificationService(eventBus, [emailAdapter]);

      await notificationService.sendNotification({
        type: 'system_alert',
        recipient: 'admin@example.com',
        subject: 'Test',
        body: 'Test body',
        channel: 'email',
      });

      expect(notificationService.getNotificationCount()).toBe(1);
      expect(historyService.getCount()).toBe(0);
    });
  });
});
